767	static std::string common_chat_template_direct_apply_impl(
768	    const common_chat_template & tmpl,
769	    const autoparser::generation_params & inputs,
770	    const std::optional<json> & messages_override = std::nullopt,
771	    const std::optional<json> & tools_override = std::nullopt,
772	    const std::optional<json> & additional_context = std::nullopt) {
773	    jinja::context ctx(tmpl.source());
774	
775	    nlohmann::ordered_json inp = nlohmann::ordered_json{
776	        {"messages", messages_override.has_value() ? *messages_override : inputs.messages},
777	        {"bos_token", tmpl.bos_token()},
778	        {"eos_token", tmpl.eos_token()},
779	        {"enable_thinking", inputs.enable_thinking},
780	    };
781	    if (tools_override.has_value() || !inputs.tools.empty()) {
782	        inp["tools"] = tools_override.has_value() ? *tools_override : inputs.tools;
783	    }
